import { useState, useMemo, useCallback } from "react";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useDeleteRestaurant, useBatchDeleteRestaurants, useAdminRestaurants, useToggleRestaurantVisibility, useBatchUpdateRestaurants } from "@/hooks/useAdmin";
import { useUserRole } from "@/hooks/useUserRole";
import { useBrands } from "@/hooks/useBrands";

import { RestaurantFormDialog } from "@/components/admin/RestaurantFormDialog";
import { DiscoverRestaurantsDialog } from "@/components/admin/DiscoverRestaurantsDialog";
import { Star, MapPin, Plus, Download, Trash2, Search, Ghost, Store, Users, Eye, EyeOff, Tag, Building2, Globe, BookOpen, Loader2, Camera } from "lucide-react";
import { exportRestaurantsToCSV } from "@/lib/exportUtils";
import { useToast } from "@/hooks/use-toast";
import { usePagination } from "@/hooks/usePagination";

const AdminRestaurants = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const { isSupervisor } = useUserRole();
  const { data: restaurants, isLoading } = useAdminRestaurants();
  const { getLocalizedField } = useLocalizedContent();
  const deleteRestaurant = useDeleteRestaurant();
  const batchDeleteRestaurants = useBatchDeleteRestaurants();
  const batchUpdateRestaurants = useBatchUpdateRestaurants();
  const toggleRestaurantVisibility = useToggleRestaurantVisibility();
  const { data: brands } = useBrands();
  const [selectedRestaurants, setSelectedRestaurants] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [typeFilter, setTypeFilter] = useState<string>("all");
  const [templateFilter, setTemplateFilter] = useState<string>("all");
  const [brandFilter, setBrandFilter] = useState<string>("all");
  const [isGeneratingStories, setIsGeneratingStories] = useState(false);
  const [isFetchingPhotos, setIsFetchingPhotos] = useState(false);
  const [storyGenProgress, setStoryGenProgress] = useState({ current: 0, total: 0, currentName: "" });
  const [photoFetchProgress, setPhotoFetchProgress] = useState({ current: 0, total: 0 });
  const [storyFilter, setStoryFilter] = useState<string>("all");

  // Batch fetch photos for restaurants (with AI smart filtering)
  const batchFetchPhotos = useCallback(async (targetRestaurants: Array<{ id: string; name: string }>) => {
    if (targetRestaurants.length === 0) return;
    setIsFetchingPhotos(true);
    setPhotoFetchProgress({ current: 0, total: targetRestaurants.length });
    
    const batchSize = 5;
    let successCount = 0;
    for (let i = 0; i < targetRestaurants.length; i += batchSize) {
      const batch = targetRestaurants.slice(i, i + batchSize);
      const ids = batch.map(r => r.id);
      setPhotoFetchProgress({ current: Math.min(i + batchSize, targetRestaurants.length), total: targetRestaurants.length });
      
      try {
        const { data, error } = await supabase.functions.invoke("fetch-place-photos", {
          body: { restaurant_ids: ids, limit: batchSize, photo_index: 0, smart_filter: true },
        });
        if (!error && data) {
          const fetched = data.results?.filter((r: any) => r.photo_url) || [];
          successCount += fetched.length;
          
          // Fallback to Street View for those without photos
          const noPhotoIds = data.results?.filter((r: any) => !r.photo_url).map((r: any) => r.id) || [];
          if (noPhotoIds.length > 0) {
            const { data: svData } = await supabase.functions.invoke("fetch-place-photos", {
              body: { restaurant_ids: noPhotoIds, limit: noPhotoIds.length, use_street_view: true },
            });
            if (svData?.results) {
              successCount += svData.results.filter((r: any) => r.photo_url).length;
            }
          }
        }
      } catch {
        // continue
      }
    }
    
    setIsFetchingPhotos(false);
    return successCount;
  }, []);

  // Batch generate missing stories + auto-fetch photos
  const handleBatchGenerateStories = useCallback(async () => {
    if (!restaurants) return;
    const missing = restaurants.filter(r => !r.photo_story_zh && !r.photo_story_en);
    if (missing.length === 0) {
      toast({ title: "✅ 所有餐厅已有建筑故事", description: `共 ${restaurants.length} 家餐厅` });
      return;
    }
    setIsGeneratingStories(true);
    setStoryGenProgress({ current: 0, total: missing.length, currentName: "" });
    let successCount = 0;
    const storySuccessIds: Array<{ id: string; name: string }> = [];
    for (let i = 0; i < missing.length; i++) {
      const r = missing[i];
      setStoryGenProgress({ current: i + 1, total: missing.length, currentName: r.name });
      try {
        const { error } = await supabase.functions.invoke("generate-store-stories", {
          body: { restaurantId: r.id, address: r.address, restaurantName: r.name },
        });
        if (!error) {
          successCount++;
          storySuccessIds.push({ id: r.id, name: r.name });
        }
      } catch {
        // continue
      }
    }
    setIsGeneratingStories(false);
    toast({ title: `故事生成完成`, description: `成功 ${successCount}/${missing.length} 家` });

    // Auto-fetch photos for restaurants that got stories and don't have photos yet
    const needPhotos = storySuccessIds.filter(s => {
      const restaurant = restaurants.find(r => r.id === s.id);
      return restaurant && !restaurant.image_url;
    });
    if (needPhotos.length > 0) {
      toast({ title: "📷 正在自动抓取配图...", description: `${needPhotos.length} 家餐厅` });
      const photoCount = await batchFetchPhotos(needPhotos);
      toast({ title: "配图抓取完成", description: `成功 ${photoCount}/${needPhotos.length} 家` });
    }
  }, [restaurants, toast, batchFetchPhotos]);

  // Batch re-fetch photos for restaurants with stories but placeholder/missing images
  const handleBatchRefetchPhotos = useCallback(async () => {
    if (!restaurants) return;
    const needPhotos = restaurants.filter(r => 
      (r.photo_story_zh || r.photo_story_en) && (!r.image_url || r.image_url.includes('placeholder'))
    );
    if (needPhotos.length === 0) {
      toast({ title: "✅ 所有有故事的餐厅已有配图" });
      return;
    }
    toast({ title: "📷 开始批量抓取配图...", description: `${needPhotos.length} 家餐厅` });
    const photoCount = await batchFetchPhotos(needPhotos.map(r => ({ id: r.id, name: r.name })));
    toast({ title: "配图抓取完成", description: `成功 ${photoCount}/${needPhotos.length} 家` });
  }, [restaurants, toast, batchFetchPhotos]);

  // Fetch merchant-restaurant associations
  const { data: merchantAssignments } = useQuery({
    queryKey: ["merchant-restaurant-assignments"],
    queryFn: async () => {
      const { data: mrData, error: mrError } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id, user_id");
      if (mrError) throw mrError;
      
      const userIds = [...new Set(mrData.map(m => m.user_id))];
      if (userIds.length === 0) return [];
      
      const { data: profiles, error: pError } = await supabase
        .from("profiles")
        .select("id, display_name")
        .in("id", userIds);
      if (pError) throw pError;
      
      const profileMap = new Map(profiles.map(p => [p.id, p.display_name]));
      return mrData.map(m => ({
        ...m,
        display_name: profileMap.get(m.user_id) || m.user_id.slice(0, 8),
      }));
    },
  });

  // Group merchants by restaurant_id
  const merchantsByRestaurant = useMemo(() => {
    const map = new Map<string, Array<{ user_id: string; display_name: string }>>();
    merchantAssignments?.forEach((item) => {
      const list = map.get(item.restaurant_id) || [];
      list.push({ user_id: item.user_id, display_name: item.display_name });
      map.set(item.restaurant_id, list);
    });
    return map;
  }, [merchantAssignments]);

  // Get unique restaurant types
  const restaurantTypes = useMemo(() => {
    if (!restaurants) return [];
    const types = new Set<string>();
    restaurants.forEach(r => {
      const restaurantTypes = getLocalizedField(r, "type");
      if (Array.isArray(restaurantTypes)) {
        restaurantTypes.forEach(type => types.add(type));
      } else if (restaurantTypes) {
        types.add(restaurantTypes);
      }
    });
    return Array.from(types);
  }, [restaurants, getLocalizedField]);

  // Story stats
  const storyStats = useMemo(() => {
    if (!restaurants) return { withStory: 0, withoutStory: 0 };
    const withStory = restaurants.filter(r => r.photo_story_zh || r.photo_story_en).length;
    return { withStory, withoutStory: restaurants.length - withStory };
  }, [restaurants]);

  // Filter restaurants based on search query, type filter, template filter, brand filter, and story filter
  const filteredRestaurants = useMemo(() => {
    if (!restaurants) return [];
    
    return restaurants.filter((restaurant) => {
      const matchesSearch = searchQuery === "" || 
        getLocalizedField(restaurant, "name").toString().toLowerCase().includes(searchQuery.toLowerCase()) ||
        restaurant.address.toLowerCase().includes(searchQuery.toLowerCase());
      
      const restaurantTypes = getLocalizedField(restaurant, "type");
      const matchesType = typeFilter === "all" || 
        (Array.isArray(restaurantTypes) 
          ? restaurantTypes.includes(typeFilter)
          : restaurantTypes === typeFilter);
      
      const restaurantTemplate = (restaurant as any).template || 'default';
      const matchesTemplate = templateFilter === "all" || restaurantTemplate === templateFilter;
      
      const matchesBrand = brandFilter === "all" || 
        (brandFilter === "none" ? !(restaurant as any).brand_id : (restaurant as any).brand_id === brandFilter);
      
      const hasStory = !!(restaurant.photo_story_zh || restaurant.photo_story_en);
      const matchesStory = storyFilter === "all" || 
        (storyFilter === "with" ? hasStory : !hasStory);
      
      return matchesSearch && matchesType && matchesTemplate && matchesBrand && matchesStory;
    });
  }, [restaurants, searchQuery, typeFilter, templateFilter, brandFilter, storyFilter, getLocalizedField]);

  // Pagination
  const {
    currentPage,
    totalPages,
    paginatedData: paginatedRestaurants,
    goToPage,
    nextPage,
    previousPage,
    canGoNext,
    canGoPrevious,
    startIndex,
    endIndex,
    totalItems,
  } = usePagination({
    data: filteredRestaurants,
    itemsPerPage: 10,
  });

  const handleExport = () => {
    if (!restaurants || restaurants.length === 0) {
      toast({
        title: t("common.error"),
        description: t("admin.noDataToExport"),
        variant: "destructive",
      });
      return;
    }

    exportRestaurantsToCSV(restaurants);
    toast({
      title: t("common.success"),
      description: t("admin.exportSuccess"),
    });
  };

  const toggleSelectRestaurant = (restaurantId: string) => {
    setSelectedRestaurants(prev =>
      prev.includes(restaurantId)
        ? prev.filter(id => id !== restaurantId)
        : [...prev, restaurantId]
    );
  };

  const toggleSelectAll = () => {
    if (selectedRestaurants.length === paginatedRestaurants?.length) {
      setSelectedRestaurants([]);
    } else {
      setSelectedRestaurants(paginatedRestaurants?.map(r => r.id) || []);
    }
  };

  const handleBatchDelete = () => {
    if (selectedRestaurants.length === 0) return;
    batchDeleteRestaurants.mutate(selectedRestaurants);
    setSelectedRestaurants([]);
  };

  if (isLoading) {
    return <div className="text-center">{t("common.loading")}</div>;
  }

  return (
    <div className="space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold mb-2">{t("admin.restaurantManagement")}</h1>
            <p className="text-muted-foreground">{t("admin.manageRestaurants")}</p>
          </div>
          <div className="flex gap-2 flex-wrap">
            <DiscoverRestaurantsDialog
              trigger={
                <Button variant="outline" className="flex-1 sm:flex-initial">
                  <Globe className="mr-2 h-4 w-4" />
                  搜索亚洲餐厅
                </Button>
              }
            />
            <Button
              variant="outline"
              className="flex-1 sm:flex-initial"
              onClick={handleBatchGenerateStories}
              disabled={isGeneratingStories}
            >
              {isGeneratingStories ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  {storyGenProgress.current}/{storyGenProgress.total}
                </>
              ) : (
                <>
                  <BookOpen className="mr-2 h-4 w-4" />
                  批量生成故事
                </>
              )}
            </Button>
            <Button
              variant="outline"
              className="flex-1 sm:flex-initial"
              onClick={handleBatchRefetchPhotos}
              disabled={isFetchingPhotos}
            >
              {isFetchingPhotos ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  {photoFetchProgress.current}/{photoFetchProgress.total}
                </>
              ) : (
                <>
                  <Camera className="mr-2 h-4 w-4" />
                  批量抓取配图
                </>
              )}
            </Button>
            <Button variant="outline" onClick={handleExport} className="flex-1 sm:flex-initial">
              <Download className="mr-2 h-4 w-4" />
              <span className="hidden sm:inline">{t("admin.exportCSV")}</span>
            </Button>
            <RestaurantFormDialog
              trigger={
                <Button className="flex-1 sm:flex-initial">
                  <Plus className="mr-2 h-4 w-4" />
                  {t("admin.addRestaurant")}
                </Button>
              }
            />
          </div>
        </div>

        {/* Search and Filter */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex gap-4 flex-wrap">
              <div className="flex-1 min-w-[200px]">
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder={t("admin.searchRestaurants")}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="pl-9"
                  />
                </div>
              </div>
              <Select value={templateFilter} onValueChange={setTemplateFilter}>
                <SelectTrigger className="w-[160px]">
                  <SelectValue placeholder={t("admin.filterByTemplate")} />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">
                    <span className="flex items-center gap-2">
                      {t("admin.allTemplates")}
                    </span>
                  </SelectItem>
                  <SelectItem value="default">
                    <span className="flex items-center gap-2">
                      <Store className="h-4 w-4" />
                      {t("admin.standardRestaurant")}
                    </span>
                  </SelectItem>
                  <SelectItem value="ghost">
                    <span className="flex items-center gap-2">
                      <Ghost className="h-4 w-4" />
                      {t("admin.ghostRestaurant")}
                    </span>
                  </SelectItem>
                </SelectContent>
              </Select>
              <Select value={typeFilter} onValueChange={setTypeFilter}>
                <SelectTrigger className="w-[180px]">
                  <SelectValue placeholder={t("admin.filterByType")} />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">{t("admin.allTypes")}</SelectItem>
                  {restaurantTypes.map((type) => (
                    <SelectItem key={type} value={type}>
                      {type}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Select value={brandFilter} onValueChange={setBrandFilter}>
                <SelectTrigger className="w-[180px]">
                  <SelectValue placeholder={t("admin.brand.filterByBrand", "按品牌筛选")} />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">{t("admin.brand.allBrands", "全部品牌")}</SelectItem>
                  <SelectItem value="none">{t("admin.brand.noBrand", "无品牌")}</SelectItem>
                  {brands?.map((brand) => (
                    <SelectItem key={brand.id} value={brand.id}>
                      <span className="flex items-center gap-2">
                        <Building2 className="h-3 w-3" />
                        {getLocalizedField(brand, "name")}
                      </span>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Select value={storyFilter} onValueChange={setStoryFilter}>
                <SelectTrigger className="w-[140px]">
                  <SelectValue placeholder="故事状态" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">全部</SelectItem>
                  <SelectItem value="with">
                    <span className="flex items-center gap-2">
                      <BookOpen className="h-3 w-3" />
                      有故事 ({storyStats.withStory})
                    </span>
                  </SelectItem>
                  <SelectItem value="without">
                    <span className="flex items-center gap-2">
                      <BookOpen className="h-3 w-3" />
                      无故事 ({storyStats.withoutStory})
                    </span>
                  </SelectItem>
                </SelectContent>
              </Select>

            </div>
          </CardContent>
        </Card>

        {/* Batch Operations */}
        {!isSupervisor && selectedRestaurants.length > 0 && (
          <Card className="bg-muted/50">
            <CardContent className="pt-6">
              <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                <span className="font-medium">
                  {t("admin.selectedCount", { count: selectedRestaurants.length })}
                </span>

                <div className="flex gap-2 flex-wrap w-full sm:w-auto">
                  {/* Batch Show */}
                  <Button
                    variant="outline"
                    size="sm"
                    className="flex-1 sm:flex-initial"
                    onClick={() => {
                      batchUpdateRestaurants.mutate({ ids: selectedRestaurants, updates: { visible: true } });
                      setSelectedRestaurants([]);
                    }}
                  >
                    <Eye className="mr-2 h-4 w-4" />
                    {t("admin.batchShow", "批量显示")}
                  </Button>

                  {/* Batch Hide */}
                  <Button
                    variant="outline"
                    size="sm"
                    className="flex-1 sm:flex-initial"
                    onClick={() => {
                      batchUpdateRestaurants.mutate({ ids: selectedRestaurants, updates: { visible: false } });
                      setSelectedRestaurants([]);
                    }}
                  >
                    <EyeOff className="mr-2 h-4 w-4" />
                    {t("admin.batchHide", "批量隐藏")}
                  </Button>

                  {/* Batch Set Brand */}
                  <Select onValueChange={(brandId) => {
                    const updates = brandId === "remove" 
                      ? { brand_id: null, is_chain: false } 
                      : { brand_id: brandId, is_chain: true };
                    batchUpdateRestaurants.mutate({ ids: selectedRestaurants, updates });
                    setSelectedRestaurants([]);
                  }}>
                    <SelectTrigger className="w-[160px]">
                      <span className="flex items-center gap-2">
                        <Building2 className="h-4 w-4" />
                        {t("admin.batchSetBrand", "设置品牌")}
                      </span>
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="remove">{t("admin.brand.removeBrand", "移除品牌")}</SelectItem>
                      {brands?.map((brand) => (
                        <SelectItem key={brand.id} value={brand.id}>
                          {getLocalizedField(brand, "name")}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>

                  <AlertDialog>
                    <AlertDialogTrigger asChild>
                      <Button variant="destructive" size="sm" className="flex-1 sm:flex-initial">
                        <Trash2 className="mr-2 h-4 w-4" />
                        {t("admin.batchDelete")}
                      </Button>
                    </AlertDialogTrigger>
                    <AlertDialogContent className="max-w-[90vw] sm:max-w-[425px]">
                      <AlertDialogHeader>
                        <AlertDialogTitle>{t("admin.confirmBatchDelete")}</AlertDialogTitle>
                        <AlertDialogDescription>
                          {t("admin.batchDeleteWarning", { count: selectedRestaurants.length })}
                        </AlertDialogDescription>
                      </AlertDialogHeader>
                      <AlertDialogFooter>
                        <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
                        <AlertDialogAction onClick={handleBatchDelete}>
                          {t("common.delete")}
                        </AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>

                  <Button variant="outline" size="sm" onClick={() => setSelectedRestaurants([])} className="flex-1 sm:flex-initial">
                    {t("admin.clearSelection")}
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Pagination Info and Select All */}
        <div className="flex items-center justify-between pb-2 border-b">
          <div className="flex items-center gap-2">
            {!isSupervisor && (
              <>
                <Checkbox
                  checked={selectedRestaurants.length === paginatedRestaurants?.length && paginatedRestaurants.length > 0}
                  onCheckedChange={toggleSelectAll}
                />
                <span className="font-medium">{t("admin.selectAll")}</span>
              </>
            )}
          </div>
          <span className="text-sm text-muted-foreground">
            {t("admin.showing")} {startIndex}-{endIndex} {t("admin.of")} {totalItems}
          </span>
        </div>

        <div className="grid gap-4">
          {paginatedRestaurants?.map((restaurant) => (
            <Card key={restaurant.id}>
              <div className="flex flex-col md:flex-row md:items-center">
                <div className="p-4 flex items-start md:self-start">
                  {!isSupervisor && (
                    <Checkbox
                      checked={selectedRestaurants.includes(restaurant.id)}
                      onCheckedChange={() => toggleSelectRestaurant(restaurant.id)}
                      className="mt-1"
                    />
                  )}
                </div>
                {restaurant.image_url && (
                  <div className="w-full md:w-48 h-48 flex items-center justify-center overflow-hidden mx-auto md:mx-0 flex-shrink-0">
                    <img
                      src={restaurant.image_url}
                      alt={String(getLocalizedField(restaurant, "name"))}
                      className="object-cover object-center w-full h-full"
                    />
                  </div>
                )}
                <div className="flex-1">
                  <CardHeader>
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2">
                      <CardTitle className="text-lg md:text-xl">{getLocalizedField(restaurant, "name")}</CardTitle>
                      <div className="flex items-center gap-2">
                        <div className="flex items-center gap-1">
                          <Star className="h-4 w-4 fill-accent text-accent" />
                          <span className="font-medium">{restaurant.rating || 0}</span>
                        </div>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="flex flex-wrap gap-2 mb-4">
                      {(restaurant as any).template === 'ghost' && (
                        <Badge variant="secondary" className="bg-primary/10 text-primary border-primary/20">
                          <Ghost className="h-3 w-3 mr-1" />
                          {t("admin.ghostRestaurant")}
                        </Badge>
                      )}
                      {(restaurant.photo_story_zh || restaurant.photo_story_en) ? (
                        <Badge variant="outline" className="text-green-600 border-green-300 bg-green-50 dark:bg-green-950/30">
                          <BookOpen className="h-3 w-3 mr-1" />
                          有故事
                        </Badge>
                      ) : (
                        <Badge variant="outline" className="text-orange-500 border-orange-300 bg-orange-50 dark:bg-orange-950/30">
                          <BookOpen className="h-3 w-3 mr-1" />
                          无故事
                        </Badge>
                      )}
                      {(Array.isArray(getLocalizedField(restaurant, "type")) 
                        ? getLocalizedField(restaurant, "type") 
                        : [getLocalizedField(restaurant, "type")]
                      ).map((type, idx) => (
                        <Badge key={idx}>{type}</Badge>
                      ))}
                    </div>
                    {(() => {
                      const merchants = merchantsByRestaurant.get(restaurant.id);
                      if (merchants && merchants.length > 0) {
                        return (
                          <div className="flex items-center gap-2 flex-wrap mb-4">
                            <Users className="h-3.5 w-3.5 text-muted-foreground flex-shrink-0" />
                            <span className="text-xs text-muted-foreground">{t("admin.associatedMerchants", "关联负责人")}:</span>
                            {merchants.map((m) => (
                              <Badge key={m.user_id} variant="outline" className="text-xs">
                                {m.display_name}
                              </Badge>
                            ))}
                          </div>
                        );
                      }
                      return null;
                    })()}
                    <div className="space-y-4">
                      <div className="flex items-center justify-between p-3 border rounded-lg">
                        <div className="space-y-0.5">
                          <Label htmlFor={`visible-${restaurant.id}`} className="text-sm font-medium">
                            {t("admin.frontendDisplay")}
                          </Label>
                          <div className="text-xs text-muted-foreground">
                            {restaurant.visible ? t("admin.restaurantShown") : t("admin.restaurantHidden")}
                          </div>
                        </div>
                        <Switch
                          id={`visible-${restaurant.id}`}
                          checked={restaurant.visible ?? true}
                          onCheckedChange={(checked) => 
                            toggleRestaurantVisibility.mutate({ 
                              restaurantId: restaurant.id, 
                              visible: checked 
                            })
                          }
                        />
                      </div>
                      <div className="flex gap-2 flex-wrap">
                        <Button variant="outline" size="sm" asChild className="flex-1 sm:flex-initial">
                          <Link to={`/restaurant/${restaurant.id}`} state={{ from: "admin" }}>{t("admin.view")}</Link>
                        </Button>
                        <RestaurantFormDialog
                          restaurant={restaurant}
                          trigger={
                            <Button variant="outline" size="sm" className="flex-1 sm:flex-initial">
                              {t("common.edit")}
                            </Button>
                          }
                        />
                        {!isSupervisor && (
                          <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button variant="outline" size="sm" className="flex-1 sm:flex-initial">
                                {t("common.delete")}
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent className="max-w-[90vw] sm:max-w-[425px]">
                              <AlertDialogHeader>
                                <AlertDialogTitle>{t("admin.confirmDelete")}</AlertDialogTitle>
                                <AlertDialogDescription>
                                  {t("admin.deleteRestaurantWarning")}
                                </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
                                <AlertDialogAction
                                  onClick={() => deleteRestaurant.mutate(restaurant.id)}
                                >
                                  {t("common.delete")}
                                </AlertDialogAction>
                              </AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </div>
              </div>
            </Card>
          ))}
        </div>

        {/* Pagination Controls */}
        {totalPages > 1 && (
          <Pagination className="mt-6">
            <PaginationContent>
              <PaginationItem>
                <PaginationPrevious
                  onClick={previousPage}
                  className={!canGoPrevious ? "pointer-events-none opacity-50" : "cursor-pointer"}
                />
              </PaginationItem>

              {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => {
                if (
                  page === 1 ||
                  page === totalPages ||
                  (page >= currentPage - 1 && page <= currentPage + 1)
                ) {
                  return (
                    <PaginationItem key={page}>
                      <PaginationLink
                        onClick={() => goToPage(page)}
                        isActive={currentPage === page}
                        className="cursor-pointer"
                      >
                        {page}
                      </PaginationLink>
                    </PaginationItem>
                  );
                }
                if (page === currentPage - 2 || page === currentPage + 2) {
                  return (
                    <PaginationItem key={page}>
                      <PaginationEllipsis />
                    </PaginationItem>
                  );
                }
                return null;
              })}

              <PaginationItem>
                <PaginationNext
                  onClick={nextPage}
                  className={!canGoNext ? "pointer-events-none opacity-50" : "cursor-pointer"}
              />
            </PaginationItem>
          </PaginationContent>
        </Pagination>
      )}
    </div>
  );
};

export default AdminRestaurants;
